from flask import Flask, redirect, url_for

app = Flask(__name__)

@app.route('/')
def index():
    return "Ana sayfa. '/redirect' adresine gidersen yönlendirileceksin."

@app.route('/redirect')
def do_redirect():
    # Bu endpoint'e ulaşıldığında kullanıcıyı '/target' adresine yönlendir.
    return redirect(url_for('target_page'))

@app.route('/target')
def target_page():
    return "Yönlendirme başarılı! Bu, hedef sayfadır."

if __name__ == '__main__':
    app.run(debug=True)
